import random
from dataclasses import dataclass, field
from typing import Any, Optional

@dataclass
class Experience:
    task_id: str
    input: Any
    output: Any
    reward: float = 0.0
    timestamp: int = 0

class ReservoirReplayBuffer:
    """
    Fixed-capacity buffer that maintains a uniform random sample of all
    experiences seen so far. Any experience has equal probability of
    being in the buffer regardless of arrival time.
    """
    def __init__(self, capacity: int):
        self.capacity = capacity
        self.buffer: list[Experience] = []
        self._total_seen = 0

    def add(self, exp: Experience) -> None:
        self._total_seen += 1
        exp.timestamp = self._total_seen
        if len(self.buffer) < self.capacity:
            self.buffer.append(exp)
        else:
            # Replace a random slot with probability capacity / total_seen
            j = random.randint(0, self._total_seen - 1)
            if j < self.capacity:
                self.buffer[j] = exp

    def sample(self, n: int) -> list[Experience]:
        return random.sample(self.buffer, min(n, len(self.buffer)))

    def sample_by_task(self, task_id: str, n: int) -> list[Experience]:
        task_exps = [e for e in self.buffer if e.task_id == task_id]
        return random.sample(task_exps, min(n, len(task_exps)))

    def task_distribution(self) -> dict[str, int]:
        from collections import Counter
        return dict(Counter(e.task_id for e in self.buffer))

    def __len__(self) -> int:
        return len(self.buffer)


# Demo: 500 experiences, capacity 100 — all timestamps equally represented
if __name__ == "__main__":
    buf = ReservoirReplayBuffer(capacity=100)
    for i in range(500):
        buf.add(Experience(task_id="qa", input=f"q_{i}", output=f"a_{i}", reward=random.random()))
    samples = buf.sample(5)
    print(f"Buffer size: {len(buf)}")
    print(f"Sample timestamps: {sorted(s.timestamp for s in samples)}")
    # Timestamps spread across 1-500, not clustered near 500
